11	export default function ItInboundPage() {
12	  const router = useRouter();
13	  const { user } = useAuth();
14	  const [form, setForm] = useState({
15	    id: "",
16	    sn: "",
17	    modelId: "",
18	    purchaseDate: "",
19	  });
20	  const [submitting, setSubmitting] = useState(false);
21	  const [error, setError] = useState<string | null>(null);
22	  const [success, setSuccess] = useState("");
23	
24	  const handleSubmit = async (e: React.FormEvent) => {
25	    e.preventDefault();
26	    setError(null);
27	    setSuccess("");
28	    if (!form.id || !form.sn || !form.modelId || !form.purchaseDate) {
29	      setError("请填写所有必填字段");
30	      return;
31	    }
32	    setSubmitting(true);
33	    try {
34	      await apiFetch("/api/it/assets/inbound", {
35	        method: "POST",
36	        body: {
37	          id: form.id,
38	          sn: form.sn,
39	          modelId: form.modelId,
40	          purchaseDate: form.purchaseDate,
41	        },
42	      });
43	      setSuccess("入库成功");
44	      setForm({ id: "", sn: "", modelId: "", purchaseDate: "" });
45	    } catch (err) {
46	      setError(err instanceof Error ? err.message : "入库失败");
47	    } finally {
48	      setSubmitting(false);
49	    }
50	  };
51	
52	  if (!user) return null;
53	  if (user.role !== "IT_ADMIN") {
54	    return (
55	      <div className="flex flex-1 items-center justify-center p-4">
56	        <p className="text-muted-foreground">仅 IT 管理员可访问此页面</p>
57	      </div>
58	    );
59	  }
60	
61	  return (
62	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-md mx-auto w-full">
63	      <PageHeader title="资产入库" description="将新资产录入系统" />
64	
65	      <form onSubmit={handleSubmit} className="space-y-4">
66	        <div className="space-y-2">
67	          <label className="text-sm font-medium">资产 ID *</label>
68	          <Input
69	            value={form.id}
70	            onChange={(e) => setForm((f) => ({ ...f, id: e.target.value }))}
71	            placeholder="例如: AST-001"
72	          />
73	        </div>
74	
75	        <div className="space-y-2">
76	          <label className="text-sm font-medium">序列号 SN *</label>
77	          <Input
78	            value={form.sn}
79	            onChange={(e) => setForm((f) => ({ ...f, sn: e.target.value }))}
80	            placeholder="例如: SN-2024-001"
81	          />
82	        </div>
83	
84	        <div className="space-y-2">
85	          <label className="text-sm font-medium">型号 ID *</label>
86	          <Input
87	            value={form.modelId}
88	            onChange={(e) => setForm((f) => ({ ...f, modelId: e.target.value }))}
89	            placeholder="例如: macbook-pro-m3-2024"
90	          />
91	        </div>
92	
93	        <div className="space-y-2">
94	          <label className="text-sm font-medium">采购日期 *</label>
95	          <Input
96	            type="date"
97	            value={form.purchaseDate}
98	            onChange={(e) => setForm((f) => ({ ...f, purchaseDate: e.target.value }))}
99	          />
100	        </div>
101	
102	        {error !== null && (
103	          <div className="rounded-lg bg-destructive/10 px-3 py-2 text-sm text-destructive">
104	            {error}
105	          </div>
106	        )}
107	
108	        {success && (
109	          <p className="text-sm text-status-green">{success}</p>
110	        )}
111	
112	        <Button type="submit" disabled={submitting} className="w-full">
113	          {submitting ? "提交中..." : "确认入库"}
114	        </Button>
115	      </form>
116	    </div>
117	  );
118	}
