3	import { useEffect, useState } from "react";
4	import Link from "next/link";
5	import { useAuth } from "@/lib/auth-context";
6	import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
7	import { Button } from "@/components/ui/button";
8	import { Skeleton } from "@/components/ui/skeleton";
9	import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
10	import { EmptyState } from "@/components/empty-state";
11	import { TicketStatusBadge } from "@/components/ticket-status-badge";
12	import { PageHeader } from "@/components/page-header";
13	import { Inbox } from "lucide-react";
14	
15	interface AssetItem {
16	  id: string;
17	  model?: { modelName: string; brandName: string; category: string };
18	  status: string;
19	  warrantyExpiry: string;
20	}
21	
22	interface TicketItem {
23	  id: string;
24	  type: string;
25	  status: string;
26	  reason: string;
27	  createdAt: string;
28	  targetModel?: { modelName: string };
29	}
