31	export default function HomePage() {
32	  const { user } = useAuth();
33	  const [assets, setAssets] = useState<AssetItem[]>([]);
34	  const [tickets, setTickets] = useState<TicketItem[]>([]);
35	  const [loading, setLoading] = useState(true);
36	  const [error, setError] = useState<string | null>(null);
37	
38	  const fetchData = async () => {
39	    setLoading(true);
40	    setError(null);
41	    try {
42	      const [assetRes, ticketRes] = await Promise.all([
43	        apiFetch<PaginatedResponse<AssetItem>>("/api/assets/mine", { params: { page: 1, pageSize: 100 } }),
44	        apiFetch<PaginatedResponse<TicketItem>>("/api/tickets", { params: { page: 1, pageSize: 5 } }),
45	      ]);
46	      setAssets(assetRes.data);
47	      setTickets(ticketRes.data);
48	    } catch (err) {
49	      setError(err instanceof Error ? err.message : "加载失败");
50	    } finally {
51	      setLoading(false);
52	    }
53	  };
54	
55	  useEffect(() => {
56	    fetchData();
57	  }, []);
58	
59	  const inUseCount = assets.filter((a) => a.status === "IN_USE" || a.status === "ASSIGNED").length;
60	  const repairCount = assets.filter((a) => a.status === "REPAIRING").length;
61	  const totalCount = assets.length;
62	
63	  if (loading) {
64	    return (
65	      <div className="flex flex-1 items-center justify-center">
66	        <div className="space-y-4 w-full max-w-5xl px-4">
67	          <Skeleton className="h-8 w-48" />
68	          <div className="grid grid-cols-3 gap-4">
69	            {[1, 2, 3].map((i) => (
70	              <Skeleton key={i} className="h-24 rounded-lg" />
71	            ))}
72	          </div>
73	          <Skeleton className="h-64 rounded-lg" />
74	        </div>
75	      </div>
76	    );
77	  }
78	
79	  if (!user) {
80	    return (
81	      <div className="flex flex-1 items-center justify-center px-4">
82	        <p className="text-muted-foreground">请先登录</p>
83	      </div>
84	    );
85	  }
86	
87	  if (error !== null) {
88	    return (
89	      <div className="flex flex-1 flex-col items-center justify-center gap-4 px-4">
90	        <p className="text-destructive">{error}</p>
91	        <Button onClick={fetchData}>重试</Button>
92	      </div>
93	    );
94	  }
95	
96	  return (
97	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-5xl mx-auto w-full">
98	      <PageHeader
99	        title={`欢迎, ${user.name}`}
100	        description={
101	          user.role === "IT_ADMIN"
102	            ? "IT 管理控制台"
103	            : user.role === "MANAGER"
104	              ? "部门管理面板"
105	              : user.role === "EXECUTIVE"
106	                ? "高管仪表盘"
107	                : "我的工作台"
108	        }
109	      />
110	
111	      {/* Stats Cards */}
112	      <div className="grid grid-cols-3 gap-4">
113	        <Card>
114	          <CardContent>
115	            <p className="text-sm text-muted-foreground">总资产</p>
116	            <p className="text-3xl font-bold">{totalCount}</p>
117	          </CardContent>
118	        </Card>
119	        <Card>
120	          <CardContent>
121	            <p className="text-sm text-muted-foreground">使用中</p>
122	            <p className="text-3xl font-bold">{inUseCount}</p>
123	          </CardContent>
124	        </Card>
125	        <Card>
126	          <CardContent>
127	            <p className="text-sm text-muted-foreground">维修中</p>
128	            <p className="text-3xl font-bold">{repairCount}</p>
129	          </CardContent>
130	        </Card>
131	      </div>
132	
133	      {/* Quick Actions */}
134	      <div className="flex flex-wrap gap-2">
135	        <Link href="/my-assets">
136	          <Button variant="outline">我的资产</Button>
137	        </Link>
138	        <Link href="/apply">
139	          <Button variant="outline">申领设备</Button>
140	        </Link>
141	        <Link href="/tickets">
142	          <Button variant="outline">我的工单</Button>
143	        </Link>
144	        <Link href="/chat">
145	          <Button variant="outline">AI 助手</Button>
146	        </Link>
147	        {user.role === "MANAGER" && (
148	          <Link href="/approvals">
149	            <Button variant="outline">待审批</Button>
150	          </Link>
151	        )}
152	        {user.role === "IT_ADMIN" && (
153	          <Link href="/it/home">
154	            <Button variant="outline">IT 管理</Button>
155	          </Link>
156	        )}
157	        {user.role === "EXECUTIVE" && (
158	          <Link href="/exec/dashboard">
159	            <Button variant="outline">数据看板</Button>
160	          </Link>
161	        )}
162	      </div>
163	
164	      {/* Recent Tickets */}
165	      <div>
166	        <div className="flex items-center justify-between mb-3">
167	          <h2 className="text-lg font-semibold">最近工单</h2>
168	          <Link href="/tickets" className="text-sm text-primary underline-offset-4 hover:underline">
169	            查看全部
170	          </Link>
171	        </div>
172	        {tickets.length === 0 ? (
173	          <EmptyState icon={Inbox} title="暂无工单" />
174	        ) : (
175	          <div className="space-y-2">
176	            {tickets.map((t) => (
177	              <Link
178	                key={t.id}
179	                href={`/tickets/${t.id}`}
180	                className="block rounded-lg border p-3 transition-colors hover:bg-muted/50"
181	              >
182	                <div className="flex items-center justify-between">
183	                  <span className="font-medium">
184	                    {t.type === "APPLY" ? "申领" : t.type === "REPAIR" ? "报修" : t.type === "RETURN" ? "归还" : "调拨"}{" "}
185	                    {t.targetModel?.modelName ?? ""}
186	                  </span>
187	                  <TicketStatusBadge status={t.status} />
188	                </div>
189	                <p className="mt-1 text-sm text-muted-foreground line-clamp-1">{t.reason}</p>
190	              </Link>
191	            ))}
192	          </div>
193	        )}
194	      </div>
195	    </div>
196	  );
197	}
